python3 - <<'PY'
import json,urllib.request,urllib.error,os
key=os.environ["N8N_API_KEY"]; apib="https://irynakarmazina.app.n8n.cloud/api/v1"
H={"X-N8N-API-KEY":key,"User-Agent":"vps"}
def req(url,method="GET"):
    return urllib.request.urlopen(urllib.request.Request(url,method=method,headers=H),timeout=40)
wfs=json.load(req(apib+"/workflows?limit=200")).get("data",[])
for w in wfs:
    nm=w.get("name",""); wid=w.get("id")
    if nm.startswith("TEMP"):
        try:
            req(apib+"/workflows/"+wid,method="DELETE"); print("DELETED",wid,nm)
        except urllib.error.HTTPError as e: print("del_err",wid,e.code)
print("remaining TEMP:",[w["name"] for w in json.load(req(apib+"/workflows?limit=200")).get("data",[]) if w.get("name","").startswith("TEMP")])
PY
